import { type CSSProperties, useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useAuth } from '../context/AuthContext';
import { ensureTournamentTableConnection, getCachedTournamentTable } from '../lib/tournamentConnections';
import styles from './TournamentLobby.module.css';

interface TournamentRow {
  id: number;
  tournament_name: string;
  start_date: string;
  max_players: number;
  min_players: number;
  players: string[];
  ranked: boolean;
  time_per_level: number;
}

interface ProfileRow {
  user_id: string;
  username: string;
  elo: number;
}

function formatCountdown(value: string) {
  const diff = new Date(value).getTime() - Date.now();
  if (diff <= 0) return 'Démarré';

  const totalMinutes = Math.ceil(diff / 60_000);
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  if (hours <= 0) return `${minutes} min`;
  return `${hours}h${String(minutes).padStart(2, '0')}`;
}

function countdownProgress(value: string) {
  const diff = new Date(value).getTime() - Date.now();
  const reference = 90 * 60_000;
  if (diff <= 0) return 360;
  return Math.max(18, Math.min(342, 360 - (diff / reference) * 360));
}

function roundBlind(value: number) {
  const power = Math.pow(10, Math.floor(Math.log10(value)));
  const significantMultiples = [1, 1.25, 1.5, 1.75, 2, 2.5, 3, 3.5, 4, 4.5, 5, 6.5, 7, 7.5, 8, 8.5, 9, 9.5, 10];

  return significantMultiples.reduce((closest, multiple) => {
    const candidate = multiple * power;
    return Math.abs(candidate - value) < Math.abs(closest - value) ? candidate : closest;
  }, significantMultiples[0] * power);
}

function getCurrentLevelIndex(tournament: TournamentRow | null) {
  if (!tournament) return 0;

  const levelDurationMs = Math.max(tournament.time_per_level, 1) * 60_000;
  const elapsedMs = Date.now() - new Date(tournament.start_date).getTime();
  if (elapsedMs <= 0) return 0;

  return Math.max(0, Math.floor(elapsedMs / levelDurationMs));
}

function buildLevels(minutes: number, startLevelIndex: number) {
  const rows = [];
  let smallBlind = 25;

  for (let index = 0; index < startLevelIndex + 7; index += 1) {
    if (index >= startLevelIndex) {
      rows.push({
        level: index + 1,
        duration: `${minutes || 5}:00`,
        smallBlind,
        bigBlind: smallBlind * 2,
        isCurrent: index === startLevelIndex,
      });
    }

    smallBlind = roundBlind(smallBlind * 1.25);
  }

  return rows;
}

export default function TournamentLobby() {
  const navigate = useNavigate();
  const { tournamentId } = useParams();
  const { user } = useAuth();
  const numericTournamentId = Number(tournamentId);

  const [tournament, setTournament] = useState<TournamentRow | null>(null);
  const [profiles, setProfiles] = useState<ProfileRow[]>([]);
  const [tableId, setTableId] = useState<number | null>(null);
  const [feedback, setFeedback] = useState('');

  const joined = Boolean(user && tournament?.players.includes(user.id));
  const playerRows = useMemo(() => {
    return (tournament?.players ?? []).map((playerId, index) => {
      const profile = profiles.find(item => item.user_id === playerId);
      return {
        id: playerId,
        name: profile?.username ?? 'Joueur',
        elo: profile?.elo ?? '-',
        stack: index === 0 ? 100 : 100,
      };
    });
  }, [profiles, tournament]);
  const currentLevelIndex = getCurrentLevelIndex(tournament);
  const levelRows = useMemo(
    () => buildLevels(tournament?.time_per_level ?? 5, currentLevelIndex),
    [currentLevelIndex, tournament?.time_per_level],
  );
  const playersLeft = tournament?.players.length ?? 0;
  const registeredPlayers = tournament?.players.length ?? 0;
  const progress = tournament ? countdownProgress(tournament.start_date) : 0;
  const countdownStyle = {
    '--countdown-progress': `${progress}deg`,
  } as CSSProperties;

  const tableLabel = useMemo(() => {
    if (!joined) return 'Non inscrit';
    if (tableId) return `Table #${tableId}`;
    return 'Préconnexion';
  }, [joined, tableId]);

  const visiblePlayers = useMemo(() => {
    if (playerRows.length > 0) return playerRows;
    return Array.from({ length: Math.min(tournament?.min_players ?? 2, 3) }, (_, index) => ({
      id: `empty-${index}`,
      name: 'Libre',
      elo: '-',
      stack: '-',
    }));
  }, [playerRows, tournament]);

  useEffect(() => {
    if (!Number.isFinite(numericTournamentId)) {
      navigate('/tournaments');
      return;
    }

    let cancelled = false;

    const fetchTournament = async () => {
      const { data, error } = await supabase.functions.invoke('list-tournaments');
      if (cancelled) return;

      const next = ((data?.tournaments ?? []) as TournamentRow[]).find(item => item.id === numericTournamentId) ?? null;
      if (error || data?.error || !next) {
        setFeedback('Tournoi introuvable.');
        setTournament(null);
        return;
      }

      setTournament(next);
      setFeedback('');

      if (next.players.length > 0) {
        const { data: profileRows } = await supabase
          .from('profiles')
          .select('user_id, username, elo')
          .in('user_id', next.players);

        if (!cancelled) {
          setProfiles((profileRows ?? []) as ProfileRow[]);
        }
      } else {
        setProfiles([]);
      }
    };

    fetchTournament();
    const interval = window.setInterval(fetchTournament, 5000);

    return () => {
      cancelled = true;
      window.clearInterval(interval);
    };
  }, [navigate, numericTournamentId]);

  useEffect(() => {
    if (!user || !joined || !tournament) return;

    const setup = async () => {
      const cached = getCachedTournamentTable(tournament.id, user.id);
      if (cached) {
        setTableId(cached);
        return;
      }

      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.access_token) return;

      const assigned = await ensureTournamentTableConnection({
        tournamentId: tournament.id,
        userId: user.id,
        accessToken: session.access_token,
        onAssigned: setTableId,
      });
      if (assigned) setTableId(assigned);
    };

    setup();
  }, [joined, tournament, user]);

  const openTable = async () => {
    if (!user || !tournament) {
      navigate('/login');
      return;
    }

    const cached = tableId ?? getCachedTournamentTable(tournament.id, user.id);
    if (cached) {
      navigate(`/game/${cached}`, { state: { tournamentId: tournament.id } });
      return;
    }

    setFeedback('Connexion à ta table...');
    const { data: { session } } = await supabase.auth.getSession();
    if (!session?.access_token) {
      navigate('/login');
      return;
    }

    const assigned = await ensureTournamentTableConnection({
      tournamentId: tournament.id,
      userId: user.id,
      accessToken: session.access_token,
      onAssigned: setTableId,
    });

    if (assigned) {
      navigate(`/game/${assigned}`, { state: { tournamentId: tournament.id } });
    } else {
      setFeedback('Table encore indisponible.');
    }
  };

  return (
    <div className={styles.page}>
      <main className={styles.shell}>
        <section className={styles.topPanel}>
          <h1>{tournament?.tournament_name ?? 'Tournoi'}</h1>
          <div className={styles.countdownDial} style={countdownStyle}>
            <div className={styles.countdownInner}>{tournament ? formatCountdown(tournament.start_date) : '-'}</div>
          </div>
          <p>{playersLeft}/{registeredPlayers}</p>
        </section>

        <section className={styles.lobbyPanel}>
          <div className={styles.levelTable}>
            <div className={`${styles.tableRow} ${styles.tableHead}`}>
              <span>Niveau</span>
              <span>Temps</span>
              <span>SB</span>
              <span>BB</span>
            </div>
            {levelRows.map(level => (
              <div key={level.level} className={`${styles.tableRow} ${level.isCurrent ? styles.currentLevel : ''}`}>
                <strong>{level.level}</strong>
                <strong>{level.duration}</strong>
                <span>{level.smallBlind}</span>
                <strong>{level.bigBlind}</strong>
              </div>
            ))}
          </div>

          <div className={styles.playersTable}>
            <div className={`${styles.playerRow} ${styles.tableHead}`}>
              <span>Nom</span>
              <span>Elo</span>
              <span>Stack</span>
              <span />
            </div>
            {visiblePlayers.map(player => (
              <div key={player.id} className={styles.playerRow}>
                <strong>{player.name}</strong>
                <strong>{player.elo}</strong>
                <span>{player.stack}</span>
                <button className={styles.joinButton} onClick={openTable} disabled={!joined}>
                  Rejoindre
                </button>
              </div>
            ))}
          </div>
        </section>

        <div className={styles.bottomActions}>
          <span>{tableLabel}</span>
          <button className={styles.backTournamentButton} onClick={() => navigate('/tournaments')}>
            Retour aux tournois
            <span />
          </button>
        </div>

        {feedback && <p className={styles.feedback}>{feedback}</p>}
      </main>
    </div>
  );
}
